/**
 * Core types for workflow execution
 */

/**
 * Available workflow phases
 */
export type Phase =
  | "spec"
  | "security-review"
  | "testgen"
  | "exec"
  | "test"
  | "qa"
  | "loop";

/**
 * Default phases for workflow execution
 */
export const DEFAULT_PHASES: Phase[] = ["spec", "exec", "qa"];

/**
 * Configuration for workflow execution
 */
export interface ExecutionConfig {
  /** Phases to execute */
  phases: Phase[];
  /** Timeout per phase in seconds */
  phaseTimeout: number;
  /** Enable quality loop mode */
  qualityLoop: boolean;
  /** Max iterations for quality loop */
  maxIterations: number;
  /** Skip verification after exec */
  skipVerification: boolean;
  /** Run issues sequentially */
  sequential: boolean;
  /** Max concurrent issues in parallel mode (default: 3) */
  concurrency: number;
  /** Suppress per-issue spinners and console output (set true when running issues concurrently) */
  parallel: boolean;
  /** Verbose output */
  verbose: boolean;
  /** Disable smart test detection */
  noSmartTests: boolean;
  /** Dry run mode - don't actually execute */
  dryRun: boolean;
  /** Enable MCP servers in headless mode (true by default, false if --no-mcp flag used) */
  mcp: boolean;
  /**
   * Enable automatic retry with MCP fallback.
   * When true (default), failed phases are retried with MCP disabled.
   * When false (--no-retry flag), no retry attempts are made.
   */
  retry?: boolean;
  /**
   * Agent driver to use for phase execution.
   * Default: "claude-code"
   */
  agent?: string;
  /**
   * Aider-specific configuration. Passed to AiderDriver when agent is "aider".
   */
  aiderSettings?: AiderSettings;
}

/**
 * Default execution configuration
 */
export const DEFAULT_CONFIG: ExecutionConfig = {
  phases: DEFAULT_PHASES,
  phaseTimeout: 1800,
  qualityLoop: false,
  maxIterations: 3,
  skipVerification: false,
  sequential: false,
  concurrency: 3,
  parallel: false,
  verbose: false,
  noSmartTests: false,
  dryRun: false,
  mcp: true,
  retry: true,
};

// Import and re-export QaVerdict from run-log-schema (single source of truth)
import type { AiderSettings } from "../settings.js";
import type { QaVerdict } from "./run-log-schema.js";
export type { QaVerdict } from "./run-log-schema.js";

/**
 * Result of executing a single phase
 */
export interface PhaseResult {
  phase: Phase;
  success: boolean;
  durationSeconds?: number;
  error?: string;
  /** Captured output from the phase (used for parsing spec recommendations) */
  output?: string;
  /** Parsed QA verdict (only for qa phase) */
  verdict?: QaVerdict;
}

/**
 * Result of executing all phases for an issue
 */
export interface IssueResult {
  issueNumber: number;
  success: boolean;
  phaseResults: PhaseResult[];
  abortReason?: string;
  loopTriggered?: boolean;
  durationSeconds?: number;
  /** PR number if created after successful QA */
  prNumber?: number;
  /** PR URL if created after successful QA */
  prUrl?: string;
}

/**
 * CLI arguments for run command
 */
export interface RunCommandOptions {
  issues: number[];
  phases?: string;
  sequential?: boolean;
  dryRun?: boolean;
  verbose?: boolean;
  timeout?: number;
  maxIterations?: number;
  qualityLoop?: boolean;
}

/**
 * Batch of issues to run together
 */
export interface IssueBatch {
  batchNumber: number;
  issues: number[];
}

/**
 * Result of a batch execution
 */
export interface BatchResult {
  batchNumber: number;
  issueResults: IssueResult[];
  success: boolean;
}

/**
 * Zod schemas for persistent workflow state tracking
 *
 * These schemas define the structure of `.sequant/state.json` which tracks
 * the current state of all issues being processed through the workflow.
 *
 * @example
 * ```typescript
 * import { WorkflowStateSchema, type WorkflowState } from './state-schema';
 *
 * // Validate state file
 * const state = WorkflowStateSchema.parse(JSON.parse(stateContent));
 *
 * // Type-safe access
 * const issue42 = state.issues["42"];
 * console.log(issue42.currentPhase, issue42.status);
 * ```
 */

import { z } from "zod";
import { ScopeAssessmentSchema } from "../scope/types.js";

/**
 * Workflow phases in order of execution
 */
export const WORKFLOW_PHASES = [
  "spec",
  "security-review",
  "exec",
  "testgen",
  "test",
  "verify",
  "qa",
  "loop",
  "merger",
] as const;

/**
 * Phase status - tracks individual phase progress
 */
export const PhaseStatusSchema = z.enum([
  "pending", // Phase not yet started
  "in_progress", // Phase currently executing
  "completed", // Phase finished successfully
  "failed", // Phase finished with errors
  "skipped", // Phase intentionally skipped (e.g., bug labels skip spec)
]);

export type PhaseStatus = z.infer<typeof PhaseStatusSchema>;

/**
 * Issue status - tracks overall issue progress
 */
export const IssueStatusSchema = z.enum([
  "not_started", // Issue tracked but no work begun
  "in_progress", // Actively being worked on
  "waiting_for_qa_gate", // QA completed, waiting for gate approval in chain mode
  "ready_for_merge", // All phases passed, PR ready for review
  "merged", // PR merged, work complete
  "blocked", // Waiting on external input or dependency
  "abandoned", // Work stopped, will not continue
]);

export type IssueStatus = z.infer<typeof IssueStatusSchema>;

/**
 * Phase type
 */
export const PhaseSchema = z.enum([
  "spec",
  "security-review",
  "exec",
  "testgen",
  "test",
  "verify",
  "qa",
  "loop",
  "merger",
]);

export type Phase = z.infer<typeof PhaseSchema>;

/**
 * Phase marker stored in GitHub issue comments for cross-session detection.
 *
 * Embedded as HTML comments: `<!-- SEQUANT_PHASE: {...} -->`
 */
export const PhaseMarkerSchema = z.object({
  /** The workflow phase */
  phase: PhaseSchema,
  /** Phase completion status */
  status: PhaseStatusSchema,
  /** ISO 8601 timestamp */
  timestamp: z.string().datetime(),
  /** PR number if created during this phase */
  pr: z.number().int().positive().optional(),
  /** Error message if phase failed */
  error: z.string().optional(),
});

export type PhaseMarker = z.infer<typeof PhaseMarkerSchema>;

/**
 * Individual phase state within an issue
 */
export const PhaseStateSchema = z.object({
  /** Current status of the phase */
  status: PhaseStatusSchema,
  /** When the phase started (if started) */
  startedAt: z.string().datetime().optional(),
  /** When the phase completed (if completed/failed/skipped) */
  completedAt: z.string().datetime().optional(),
  /** Error message if phase failed */
  error: z.string().optional(),
  /** Number of loop iterations (for loop phase) */
  iteration: z.number().int().nonnegative().optional(),
});

export type PhaseState = z.infer<typeof PhaseStateSchema>;

/**
 * PR information for an issue
 */
export const PRInfoSchema = z.object({
  /** PR number */
  number: z.number().int().positive(),
  /** PR URL */
  url: z.string().url(),
});

export type PRInfo = z.infer<typeof PRInfoSchema>;

/**
 * Quality loop state
 */
export const LoopStateSchema = z.object({
  /** Whether quality loop is enabled */
  enabled: z.boolean(),
  /** Current iteration number */
  iteration: z.number().int().nonnegative(),
  /** Maximum iterations allowed */
  maxIterations: z.number().int().positive(),
});

export type LoopState = z.infer<typeof LoopStateSchema>;

/**
 * Acceptance criteria verification status
 */
export const ACStatusSchema = z.enum([
  "pending", // Not yet verified
  "met", // Verified as satisfied
  "not_met", // Verified as not satisfied
  "blocked", // Cannot verify due to external dependency
]);

export type ACStatus = z.infer<typeof ACStatusSchema>;

/**
 * Acceptance criteria verification method
 */
export const ACVerificationMethodSchema = z.enum([
  "unit_test",
  "integration_test",
  "browser_test",
  "manual",
]);

export type ACVerificationMethod = z.infer<typeof ACVerificationMethodSchema>;

/**
 * Individual acceptance criterion state
 */
export const AcceptanceCriterionSchema = z.object({
  /** AC identifier (e.g., "A1", "B2") */
  id: z.string(),
  /** Description of the acceptance criterion */
  description: z.string(),
  /** How this AC should be verified */
  verificationMethod: ACVerificationMethodSchema,
  /** Current verification status */
  status: ACStatusSchema,
  /** When the AC was last verified */
  verifiedAt: z.string().datetime().optional(),
  /** Additional notes about verification */
  notes: z.string().optional(),
});

export type AcceptanceCriterion = z.infer<typeof AcceptanceCriterionSchema>;

/**
 * Acceptance criteria tracking for an issue
 */
export const AcceptanceCriteriaSchema = z.object({
  /** List of acceptance criteria */
  items: z.array(AcceptanceCriterionSchema),
  /** When the AC list was extracted from the issue */
  extractedAt: z.string().datetime(),
  /** Summary counts for quick access */
  summary: z.object({
    total: z.number().int().nonnegative(),
    met: z.number().int().nonnegative(),
    notMet: z.number().int().nonnegative(),
    pending: z.number().int().nonnegative(),
    blocked: z.number().int().nonnegative(),
  }),
});

export type AcceptanceCriteria = z.infer<typeof AcceptanceCriteriaSchema>;

/**
 * Complete state for a single issue
 */
export const IssueStateSchema = z.object({
  /** GitHub issue number */
  number: z.number().int().positive(),
  /** Issue title */
  title: z.string(),
  /** Overall issue status */
  status: IssueStatusSchema,
  /** Path to the worktree (if created) */
  worktree: z.string().optional(),
  /** Branch name for this issue */
  branch: z.string().optional(),
  /** Current phase being executed or last executed */
  currentPhase: PhaseSchema.optional(),
  /** State of each phase (only phases that have been started/tracked) */
  phases: z.record(z.string(), PhaseStateSchema),
  /** PR information (if PR created) */
  pr: PRInfoSchema.optional(),
  /** Quality loop state (if loop enabled) */
  loop: LoopStateSchema.optional(),
  /** Acceptance criteria tracking (if extracted by /spec) */
  acceptanceCriteria: AcceptanceCriteriaSchema.optional(),
  /** Scope assessment result (if performed by /spec) */
  scopeAssessment: ScopeAssessmentSchema.optional(),
  /** Claude session ID (for resume) */
  sessionId: z.string().optional(),
  /** Most recent activity timestamp */
  lastActivity: z.string().datetime(),
  /** When this issue was first tracked */
  createdAt: z.string().datetime(),
});

export type IssueState = z.infer<typeof IssueStateSchema>;

/**
 * Complete workflow state schema
 *
 * This is the top-level schema for `.sequant/state.json`
 */
export const WorkflowStateSchema = z.object({
  /** Schema version for backwards compatibility */
  version: z.literal(1),
  /** When the state file was last updated */
  lastUpdated: z.string().datetime(),
  /** State for all tracked issues, keyed by issue number */
  issues: z.record(z.string(), IssueStateSchema),
});

export type WorkflowState = z.infer<typeof WorkflowStateSchema>;

/**
 * Default state file path
 */
export const STATE_FILE_PATH = ".sequant/state.json";

/**
 * Create an empty workflow state
 */
export function createEmptyState(): WorkflowState {
  return {
    version: 1,
    lastUpdated: new Date().toISOString(),
    issues: {},
  };
}

/**
 * Create initial state for a new issue
 */
export function createIssueState(
  issueNumber: number,
  title: string,
  options?: {
    worktree?: string;
    branch?: string;
    qualityLoop?: boolean;
    maxIterations?: number;
  },
): IssueState {
  const now = new Date().toISOString();

  return {
    number: issueNumber,
    title,
    status: "not_started",
    worktree: options?.worktree,
    branch: options?.branch,
    phases: {},
    loop: options?.qualityLoop
      ? {
          enabled: true,
          iteration: 0,
          maxIterations: options?.maxIterations ?? 3,
        }
      : undefined,
    lastActivity: now,
    createdAt: now,
  };
}

/**
 * Create initial phase state
 */
export function createPhaseState(status: PhaseStatus = "pending"): PhaseState {
  if (status === "in_progress") {
    return {
      status,
      startedAt: new Date().toISOString(),
    };
  }
  return { status };
}

/**
 * Create acceptance criterion
 */
export function createAcceptanceCriterion(
  id: string,
  description: string,
  verificationMethod: ACVerificationMethod = "manual",
): AcceptanceCriterion {
  return {
    id,
    description,
    verificationMethod,
    status: "pending",
  };
}

/**
 * Create acceptance criteria tracking structure
 */
export function createAcceptanceCriteria(
  items: AcceptanceCriterion[],
): AcceptanceCriteria {
  return {
    items,
    extractedAt: new Date().toISOString(),
    summary: {
      total: items.length,
      met: 0,
      notMet: 0,
      pending: items.length,
      blocked: 0,
    },
  };
}

/**
 * Update acceptance criteria summary based on item statuses
 */
export function updateAcceptanceCriteriaSummary(
  ac: AcceptanceCriteria,
): AcceptanceCriteria {
  const summary = {
    total: ac.items.length,
    met: ac.items.filter((i) => i.status === "met").length,
    notMet: ac.items.filter((i) => i.status === "not_met").length,
    pending: ac.items.filter((i) => i.status === "pending").length,
    blocked: ac.items.filter((i) => i.status === "blocked").length,
  };
  return { ...ac, summary };
}

/**
 * Zod schemas for structured workflow run logs
 *
 * These schemas define the structure of JSON logs produced by `sequant run`
 * for analysis, debugging, and automation purposes.
 *
 * @example
 * ```typescript
 * import { RunLogSchema, type RunLog } from './run-log-schema';
 *
 * // Validate a log file
 * const log = RunLogSchema.parse(JSON.parse(logContent));
 *
 * // Type-safe access
 * console.log(log.summary.passed, log.summary.failed);
 * ```
 */

import { randomUUID } from "node:crypto";
import { z } from "zod";

/**
 * Available workflow phases
 */
export const PhaseSchema = z.enum([
  "spec",
  "security-review",
  "testgen",
  "exec",
  "test",
  "qa",
  "loop",
]);

export type Phase = z.infer<typeof PhaseSchema>;

/**
 * Phase execution status
 */
export const PhaseStatusSchema = z.enum([
  "success",
  "failure",
  "timeout",
  "skipped",
]);

export type PhaseStatus = z.infer<typeof PhaseStatusSchema>;

/**
 * Issue execution status
 */
export const IssueStatusSchema = z.enum(["success", "failure", "partial"]);

export type IssueStatus = z.infer<typeof IssueStatusSchema>;

/**
 * Valid QA verdicts schema
 */
export const QaVerdictSchema = z.enum([
  "READY_FOR_MERGE",
  "AC_MET_BUT_NOT_A_PLUS",
  "AC_NOT_MET",
  "NEEDS_VERIFICATION",
]);

export type QaVerdict = z.infer<typeof QaVerdictSchema>;

/**
 * File diff statistics for a single file (AC-3)
 */
export const FileDiffStatSchema = z.object({
  /** File path relative to repository root */
  path: z.string(),
  /** Number of lines added */
  additions: z.number().int().nonnegative(),
  /** Number of lines deleted */
  deletions: z.number().int().nonnegative(),
  /** Change status */
  status: z.enum(["added", "modified", "deleted", "renamed"]),
});

export type FileDiffStat = z.infer<typeof FileDiffStatSchema>;

/**
 * Cache metrics for QA phase (AC-7)
 */
export const CacheMetricsSchema = z.object({
  /** Number of cache hits */
  hits: z.number().int().nonnegative(),
  /** Number of cache misses */
  misses: z.number().int().nonnegative(),
  /** Number of skipped checks */
  skipped: z.number().int().nonnegative(),
});

export type CacheMetrics = z.infer<typeof CacheMetricsSchema>;

/**
 * Log entry for a single phase execution
 */
export const PhaseLogSchema = z.object({
  /** Phase that was executed */
  phase: PhaseSchema,
  /** GitHub issue number */
  issueNumber: z.number().int().positive(),
  /** When the phase started */
  startTime: z.string().datetime(),
  /** When the phase ended */
  endTime: z.string().datetime(),
  /** Duration in seconds */
  durationSeconds: z.number().nonnegative(),
  /** Execution result */
  status: PhaseStatusSchema,
  /** Error message if failed */
  error: z.string().optional(),
  /** Number of iterations (for loop phase) */
  iterations: z.number().int().nonnegative().optional(),
  /** Files modified during this phase */
  filesModified: z.array(z.string()).optional(),
  /** Number of tests run (for test/qa phases) */
  testsRun: z.number().int().nonnegative().optional(),
  /** Number of tests passed */
  testsPassed: z.number().int().nonnegative().optional(),
  /** Parsed QA verdict (only for qa phase) */
  verdict: QaVerdictSchema.optional(),
  /** Git commit SHA after phase completes (AC-2) */
  commitHash: z.string().optional(),
  /** Per-file diff statistics (AC-3) */
  fileDiffStats: z.array(FileDiffStatSchema).optional(),
  /** Cache metrics for QA phase (AC-7) */
  cacheMetrics: CacheMetricsSchema.optional(),
});

export type PhaseLog = z.infer<typeof PhaseLogSchema>;

/**
 * Complete execution record for a single issue
 */
export const IssueLogSchema = z.object({
  /** GitHub issue number */
  issueNumber: z.number().int().positive(),
  /** Issue title */
  title: z.string(),
  /** Issue labels */
  labels: z.array(z.string()),
  /** Overall execution result */
  status: IssueStatusSchema,
  /** Log entries for each phase executed */
  phases: z.array(PhaseLogSchema),
  /** Total execution time in seconds */
  totalDurationSeconds: z.number().nonnegative(),
  /** PR number if created after successful QA */
  prNumber: z.number().int().positive().optional(),
  /** PR URL if created after successful QA */
  prUrl: z.string().optional(),
});

export type IssueLog = z.infer<typeof IssueLogSchema>;

/**
 * Run configuration
 */
export const RunConfigSchema = z.object({
  /** Phases that were configured to run */
  phases: z.array(PhaseSchema),
  /** Whether issues were run sequentially */
  sequential: z.boolean(),
  /** Whether quality loop was enabled */
  qualityLoop: z.boolean(),
  /** Maximum iterations for fix loops */
  maxIterations: z.number().int().positive(),
  /** Whether chain mode was enabled (each issue branches from previous) */
  chain: z.boolean().optional(),
  /** Whether QA gate was enabled (chain pauses if QA fails) */
  qaGate: z.boolean().optional(),
});

export type RunConfig = z.infer<typeof RunConfigSchema>;

/**
 * Summary statistics for a run
 */
export const RunSummarySchema = z.object({
  /** Total number of issues processed */
  totalIssues: z.number().int().nonnegative(),
  /** Number of issues that passed */
  passed: z.number().int().nonnegative(),
  /** Number of issues that failed */
  failed: z.number().int().nonnegative(),
  /** Total execution time in seconds */
  totalDurationSeconds: z.number().nonnegative(),
});

export type RunSummary = z.infer<typeof RunSummarySchema>;

/**
 * Complete run log schema
 *
 * This is the top-level schema for a workflow run log file.
 */
export const RunLogSchema = z.object({
  /** Schema version for backwards compatibility */
  version: z.literal(1),
  /** Unique identifier for this run */
  runId: z.string().uuid(),
  /** When the run started */
  startTime: z.string().datetime(),
  /** When the run ended */
  endTime: z.string().datetime(),
  /** Run configuration */
  config: RunConfigSchema,
  /** Execution logs for each issue */
  issues: z.array(IssueLogSchema),
  /** Summary statistics */
  summary: RunSummarySchema,
  /** Git commit SHA at run start (AC-2) */
  startCommit: z.string().optional(),
  /** Git commit SHA at run end (AC-2) */
  endCommit: z.string().optional(),
});

export type RunLog = z.infer<typeof RunLogSchema>;

/**
 * Default log directory paths
 */
export const LOG_PATHS = {
  /** User-level logs */
  user: "~/.sequant/logs",
  /** Project-level logs */
  project: ".sequant/logs",
} as const;

/**
 * Generate a log filename from run metadata
 *
 * @param runId - Unique run identifier
 * @param startTime - Run start time
 * @returns Filename in format: run-<timestamp>-<runId>.json
 */
export function generateLogFilename(runId: string, startTime: Date): string {
  const timestamp = startTime.toISOString().replace(/[:.]/g, "-").slice(0, 19);
  return `run-${timestamp}-${runId}.json`;
}

/**
 * Create an empty run log with initial values
 *
 * @param config - Run configuration
 * @param options - Optional fields including startCommit
 * @returns Initial RunLog structure
 */
export function createEmptyRunLog(
  config: RunConfig,
  options?: { startCommit?: string },
): Omit<RunLog, "endTime"> {
  const runId = randomUUID();
  const startTime = new Date().toISOString();

  return {
    version: 1,
    runId,
    startTime,
    config,
    issues: [],
    summary: {
      totalIssues: 0,
      passed: 0,
      failed: 0,
      totalDurationSeconds: 0,
    },
    startCommit: options?.startCommit,
  };
}

/**
 * Create a phase log entry
 *
 * @param phase - Phase being executed
 * @param issueNumber - GitHub issue number
 * @returns PhaseLog with start time set
 */
export function createPhaseLog(
  phase: Phase,
  issueNumber: number,
): Omit<PhaseLog, "endTime" | "durationSeconds" | "status"> {
  return {
    phase,
    issueNumber,
    startTime: new Date().toISOString(),
  };
}

/**
 * Complete a phase log entry
 *
 * @param phaseLog - Partial phase log
 * @param status - Final status
 * @param options - Additional fields (error, filesModified, verdict, etc.)
 * @returns Complete PhaseLog
 */
export function completePhaseLog(
  phaseLog: Omit<PhaseLog, "endTime" | "durationSeconds" | "status">,
  status: PhaseStatus,
  options?: Partial<
    Pick<
      PhaseLog,
      | "error"
      | "iterations"
      | "filesModified"
      | "testsRun"
      | "testsPassed"
      | "verdict"
      | "commitHash"
      | "fileDiffStats"
      | "cacheMetrics"
    >
  >,
): PhaseLog {
  const endTime = new Date();
  const startTime = new Date(phaseLog.startTime);
  const durationSeconds = (endTime.getTime() - startTime.getTime()) / 1000;

  return {
    ...phaseLog,
    endTime: endTime.toISOString(),
    durationSeconds,
    status,
    ...options,
  };
}

/**
 * Finalize a run log with summary statistics
 *
 * @param runLog - Partial run log
 * @param options - Optional fields including endCommit
 * @returns Complete RunLog with endTime and summary
 */
export function finalizeRunLog(
  runLog: Omit<RunLog, "endTime">,
  options?: { endCommit?: string },
): RunLog {
  const endTime = new Date();
  const startTime = new Date(runLog.startTime);
  const totalDurationSeconds = (endTime.getTime() - startTime.getTime()) / 1000;

  const passed = runLog.issues.filter(
    (i: IssueLog) => i.status === "success",
  ).length;
  const failed = runLog.issues.filter(
    (i: IssueLog) => i.status === "failure",
  ).length;

  return {
    ...runLog,
    endTime: endTime.toISOString(),
    summary: {
      totalIssues: runLog.issues.length,
      passed,
      failed,
      totalDurationSeconds,
    },
    endCommit: options?.endCommit ?? runLog.endCommit,
  };
}

